import React from "react";
import styled from "styled-components";

export const LabeledInput = ({
  placeholder,
  label,
  id,
  type,
  name,
  required,
  value,
  icon = null,
  ...props
}) => {
  return (
    <InputWrapper>
      <StyledLabel htmlFor={id}>
        {label} {!required && <span> - Optional</span>}
      </StyledLabel>
      <IconInput className={type === "file" && "file-upload"}>
        <StyledInput
          type={type}
          id={id}
          placeholder={placeholder}
          name={name}
          value={value}
          {...props}
        />
        {icon && <IconWrapper>{icon}</IconWrapper>}
      </IconInput>
    </InputWrapper>
  );
};

const InputWrapper = styled.div`
  display: flex;
  flex-direction: column;
  gap: 8px;
  width: 100%;
`;

const StyledInput = styled.input`
  background: #ffffff;
  border: 2px solid #eeedf3;
  border-radius: 5px;
  padding: 16px;
  height: 56px;
  box-sizing: border-box;
  width: 100%;

  &[type="file"] {
    display: none;
  }

  &:active,
  &:focus {
    color: #060831;
    outline: none;
    border: 2px solid #4200ff;
  }

  &:disabled {
    background: #0000001a;
    opacity: 0.5;
  }

  &::placeholder {
    font-family: "Roboto";
    font-style: normal;
    font-weight: 400;
    font-size: 14px;
    line-height: 16px;
    letter-spacing: 0.2px;
    color: #757ba9;
  }
`;

const StyledLabel = styled.label`
  font-family: "Roboto";
  font-style: normal;
  font-weight: 400;
  font-size: 14px;
  line-height: 16px;
  letter-spacing: 0.2px;
  color: #47474f;

  & span {
    color: #cacfe0;
  }
`;

const IconWrapper = styled.div`
  position: absolute;
  top: 16px;
  right: 19px;
`;

const IconInput = styled.div`
  position: relative;

  &.file-upload {
    cursor: pointer;
    background: #ffffff;
    border: 2px solid #eeedf3;
    border-radius: 5px;
    padding: 16px;
    height: 56px;
    box-sizing: border-box;
    width: 100%;

    &::before {
      content: "Upload CV";
    }

    &:active,
    &:focus {
      color: #060831;
      outline: none;
      border: 2px solid #4200ff;
    }

    &:disabled {
      background: #0000001a;
      opacity: 0.5;
    }
  }
`;
