import React from "react";
import styled from "styled-components";

export const LabeledTextarea = ({
  placeholder,
  label,
  id,
  type,
  name,
  required,
  value,
  ...props
}) => {
  return (
    <TextareaWrapper>
      <StyledLabel htmlFor={id}>
        {label} {!required && <span> - Optional</span>}
      </StyledLabel>
      <StyledTextarea
        type={type}
        id={id}
        placeholder={placeholder}
        name={name}
        value={value}
        {...props}
      />
    </TextareaWrapper>
  );
};

const TextareaWrapper = styled.div`
  display: flex;
  flex-direction: column;
  gap: 8px;
  width: 100%;
`;

const StyledTextarea = styled.textarea`
  background: #ffffff;
  border: 2px solid #eeedf3;
  border-radius: 5px;
  padding: 16px;
  height: 56px;
  box-sizing: border-box;
  font-family: "Roboto";
  font-style: normal;
  font-weight: 400;
  font-size: 14px;
  line-height: 16px;
  letter-spacing: 0.2px;
  color: #757ba9;
  resize: vertical;

  &:active,
  &:focus {
    color: #060831;
    outline: none;
    border: 2px solid #4200ff;
  }

  &:disabled {
    background: #0000001a;
    opacity: 0.5;
  }

  &::placeholder {
    font-family: "Roboto";
    font-style: normal;
    font-weight: 400;
    font-size: 14px;
    line-height: 16px;
    letter-spacing: 0.2px;
    color: #757ba9;
  }
`;

const StyledLabel = styled.label`
  font-family: "Roboto";
  font-style: normal;
  font-weight: 400;
  font-size: 14px;
  line-height: 16px;
  letter-spacing: 0.2px;
  color: #47474f;

  & span {
    color: #cacfe0;
  }
`;
